  it('never throws regardless of input', () => {
    const inputs = [
      null,
      undefined,
      42,
      true,
      {},
      [],
      new Uint8Array(4),
      '',
      'bad json',
      '{"type":"other"}',
      '{"type":"peer_exchange_request"}',
      Symbol('test'),
    ];
    for (const input of inputs) {
      expect(() => isProtocolMessage(input)).not.toThrow();
    }
  });
});

describe('initializeDiscovery', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('returns a cleanup function', () => {
    const api = createMockNetworkApi();
    const cleanup = initializeDiscovery(api);
    expect(typeof cleanup).toBe('function');
    cleanup();
  });

  it('cleanup function does not throw when called', () => {
    const api = createMockNetworkApi();
    const cleanup = initializeDiscovery(api);
    expect(() => cleanup()).not.toThrow();
  });

  it('cleanup function is safe to call multiple times', () => {
    const api = createMockNetworkApi();
    const cleanup = initializeDiscovery(api);
    expect(() => cleanup()).not.toThrow();
    expect(() => cleanup()).not.toThrow();
    expect(() => cleanup()).not.toThrow();
  });

  it('starts two interval timers (discovery and rotation)', () => {
    const setIntervalSpy = vi.spyOn(globalThis, 'setInterval');
    const api = createMockNetworkApi();
    const cleanup = initializeDiscovery(api);

    // Should have set at least 2 intervals
    expect(setIntervalSpy).toHaveBeenCalledTimes(2);

    // Verify the intervals match the constants
    const intervals = setIntervalSpy.mock.calls.map((call) => call[1]);
    expect(intervals).toContain(30000); // DISCOVERY_INTERVAL
    expect(intervals).toContain(300000); // ROTATION_INTERVAL

    cleanup();
    setIntervalSpy.mockRestore();
  });

  it('no timers remain active after cleanup', () => {
    const clearIntervalSpy = vi.spyOn(globalThis, 'clearInterval');
    const api = createMockNetworkApi();
    const cleanup = initializeDiscovery(api);

    cleanup();

    // clearInterval should have been called at least twice (once per timer)
    expect(clearIntervalSpy.mock.calls.length).toBeGreaterThanOrEqual(2);

    clearIntervalSpy.mockRestore();
  });

  it('throws on null networkApi', () => {
    expect(() => initializeDiscovery(null as any)).toThrow();
  });

  it('throws on undefined networkApi', () => {
    expect(() => initializeDiscovery(undefined as any)).toThrow();
  });

  it('throws when networkApi is missing required methods', () => {
    expect(() => initializeDiscovery({} as any)).toThrow();
    expect(() => initializeDiscovery({ getConnectedPeerCount: vi.fn() } as any)).toThrow();
  });

  it('discovery interval triggers network checks', () => {
    const api = createMockNetworkApi();
    api.getConnectedPeerCount.mockReturnValue(0);
    api.getConnectedPeerUrls.mockReturnValue([]);

    const cleanup = initializeDiscovery(api);

    // Advance time by one discovery interval (30s)
    vi.advanceTimersByTime(30000);

    // The discovery callback should have been invoked — it checks connected peer count
    expect(api.getConnectedPeerCount).toHaveBeenCalled();

    cleanup();
  });
});

